import React, { useState, useRef } from 'react';

let seq = 0;
const uid = () => `f${++seq}`;
const fmt = (b) => (b < 1024 ? `${b} B` : b < 1048576 ? `${(b / 1024).toFixed(1)} KB` : `${(b / 1048576).toFixed(1)} MB`);

export default function FileUploader() {
  const [chunkKB, setChunkKB] = useState(64);
  const [files, setFiles] = useState([]);
  const [over, setOver] = useState(false);
  const timers = useRef({});

  const upload = (file) => {
    const id = setInterval(() => {
      setFiles((cur) =>
        cur.map((f) => {
          if (f.id !== file.id) return f;
          if (f.sent >= f.total) {
            clearInterval(timers.current[f.id]);
            return f;
          }
          return { ...f, sent: f.sent + 1 };
        })
      );
    }, 200);
    timers.current[file.id] = id;
  };

  const add = (fileList) => {
    const chunkSize = chunkKB * 1024;
    const next = [...fileList].map((f) => ({
      id: uid(),
      name: f.name,
      size: f.size,
      sent: 0,
      total: Math.max(1, Math.ceil(f.size / chunkSize)),
    }));
    setFiles((cur) => [...cur, ...next]);
    next.forEach(upload);
  };

  const onDrop = (e) => {
    e.preventDefault();
    setOver(false);
    add(e.dataTransfer.files);
  };

  return (
    <div style={{ maxWidth: 420 }}>
      <label style={{ display: 'block', marginBottom: 10 }}>
        Chunk size: {chunkKB} KB
        <input type="range" min="16" max="256" step="16" value={chunkKB} onChange={(e) => setChunkKB(Number(e.target.value))} style={{ width: '100%' }} />
      </label>

      <div
        onDragOver={(e) => { e.preventDefault(); setOver(true); }}
        onDragLeave={() => setOver(false)}
        onDrop={onDrop}
        style={{ border: `2px dashed ${over ? '#2563eb' : '#cbd5e1'}`, borderRadius: 10, padding: 24, textAlign: 'center', background: over ? '#eff6ff' : '#fff' }}
      >
        <p style={{ margin: '0 0 8px' }}>Drag files here, or</p>
        <input type="file" multiple onChange={(e) => add(e.target.files)} />
      </div>

      <div style={{ marginTop: 14, display: 'flex', flexDirection: 'column', gap: 10 }}>
        {files.map((f) => {
          const pct = Math.round((f.sent / f.total) * 100);
          return (
            <div key={f.id}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13 }}>
                <span>{f.name} ({fmt(f.size)})</span>
                <span>{pct}%{pct === 100 ? ' ✓' : ''}</span>
              </div>
              <div style={{ height: 8, background: '#e5e7eb', borderRadius: 4, overflow: 'hidden' }}>
                <div style={{ width: `${pct}%`, height: '100%', background: pct === 100 ? '#16a34a' : '#2563eb', transition: 'width 0.2s' }} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

