import { Component, OnDestroy } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface UploadFile { id: string; name: string; size: number; sent: number; total: number; }

@Component({
  selector: 'app-file-uploader',
  template: `
    <div style="max-width: 420px;">
      <label style="display: block; margin-bottom: 10px;">
        Chunk size: {{ chunkKB }} KB
        <input type="range" min="16" max="256" step="16" [value]="chunkKB" (input)="chunkKB = toNum($any($event.target).value)" style="width: 100%;" />
      </label>

      <div
        (dragover)="$event.preventDefault(); over = true"
        (dragleave)="over = false"
        (drop)="onDrop($event)"
        [style.border]="'2px dashed ' + (over ? '#2563eb' : '#cbd5e1')"
        [style.background]="over ? '#eff6ff' : '#fff'"
        style="border-radius: 10px; padding: 24px; text-align: center;"
      >
        <p style="margin: 0 0 8px;">Drag files here, or</p>
        <input type="file" multiple (change)="add($any($event.target).files)" />
      </div>

      <div style="margin-top: 14px; display: flex; flex-direction: column; gap: 10px;">
        <div *ngFor="let f of files">
          <div style="display: flex; justify-content: space-between; font-size: 13px;">
            <span>{{ f.name }} ({{ fmt(f.size) }})</span>
            <span>{{ pct(f) }}%<span *ngIf="pct(f) === 100"> ✓</span></span>
          </div>
          <div style="height: 8px; background: #e5e7eb; border-radius: 4px; overflow: hidden;">
            <div [style.width.%]="pct(f)" [style.background]="pct(f) === 100 ? '#16a34a' : '#2563eb'" style="height: 100%; transition: width 0.2s;"></div>
          </div>
        </div>
      </div>
    </div>
  `,
})
export class FileUploaderComponent implements OnDestroy {
  chunkKB = 64;
  over = false;
  files: UploadFile[] = [];
  private seq = 0;
  private timers: Record<string, any> = {};

  uid(): string {
    this.seq++;
    return 'f' + this.seq;
  }

  toNum(v: string): number {
    return Number(v);
  }

  fmt(b: number): string {
    if (b < 1024) return b + ' B';
    if (b < 1048576) return (b / 1024).toFixed(1) + ' KB';
    return (b / 1048576).toFixed(1) + ' MB';
  }

  pct(f: UploadFile): number {
    return Math.round((f.sent / f.total) * 100);
  }

  upload(item: UploadFile): void {
    const id = setInterval(() => {
      if (item.sent >= item.total) {
        clearInterval(id);
        return;
      }
      item.sent++;
    }, 200);
    this.timers[item.id] = id;
  }

  add(list: FileList): void {
    const size = this.chunkKB * 1024;
    Array.from(list).forEach((f) => {
      const item: UploadFile = { id: this.uid(), name: f.name, size: f.size, sent: 0, total: Math.max(1, Math.ceil(f.size / size)) };
      this.files.push(item);
      this.upload(item);
    });
  }

  onDrop(e: DragEvent): void {
    e.preventDefault();
    this.over = false;
    if (e.dataTransfer) {
      this.add(e.dataTransfer.files);
    }
  }

  ngOnDestroy(): void {
    Object.keys(this.timers).forEach((k) => clearInterval(this.timers[k]));
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Chunked Uploader Demo</h1>
      <app-file-uploader></app-file-uploader>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, FileUploaderComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
